import { useState } from "react";

const WINNING_LINES = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],
  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],
  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function winner(board) {
  for (const [a, b, c] of WINNING_LINES) {
    const player = board[a[0]][a[1]];

    if (
      player &&
      player === board[b[0]][b[1]] &&
      player === board[c[0]][c[1]]
    ) {
      return player;
    }
  }

  return null;
}

export default function TicTacToe() {
  const [board, setBoard] = useState([
    ["", "", ""],
    ["", "", ""],
    ["", "", ""],
  ]);

  const [turn, setTurn] = useState("X");

  function play(row, col) {
    if (board[row][col]) return;

    const nextBoard = board.map(row => [...row]);
    nextBoard[row][col] = turn;

    setBoard(nextBoard);
    setTurn(turn === "X" ? "O" : "X");
  }

  function reset() {
    setBoard([
      ["", "", ""],
      ["", "", ""],
      ["", "", ""],
    ]);

    setTurn("X");
  }

  const winningPlayer = winner(board);

  return (
    <main>
      <h1>Tic Tac Toe</h1>

      <p>
        {winningPlayer ? `${winningPlayer} wins!` : `Turn: ${turn}`}
      </p>

      <table
		style={{
			// borderCollapse: "collapse",
			fontFamily: "monospace",
		}}
		>
		<tbody>
			{board.map((row, r) => (
			<tr key={r}>
				{row.map((cell, c) => (
				<td
					key={c}
					onClick={() => play(r, c)}
					style={{border: "1px solid"}}
				>
					{cell || "\u00A0"}
				</td>
				))}
			</tr>
			))}
		</tbody>
		</table>

      <p>
        <button onClick={reset}>Play Again</button>
      </p>
    </main>
  );
}
